'use client';

export function PipelineOverview() {
    const funnel = [
        {
            stage: 'Sourced',
            sublabel: 'Resumes uploaded',
            count: 8405,
            percentage: 100,
            gradient: 'linear-gradient(90deg, #5A46DA, #7B6CFF)',
            lightBg: 'rgba(90, 70, 218, 0.08)',
            pill: '#5A46DA',
        },
        {
            stage: 'AI Shortlisted',
            sublabel: 'Passed resume screen',
            count: 1248,
            percentage: 14.8,
            gradient: 'linear-gradient(90deg, #7B6CFF, #9B8CFF)',
            lightBg: 'rgba(123, 108, 255, 0.08)',
            pill: '#7B6CFF',
        },
        {
            stage: 'AI Screened',
            sublabel: 'Completed AI interview',
            count: 386,
            percentage: 4.6,
            gradient: 'linear-gradient(90deg, #0ea5e9, #38bdf8)',
            lightBg: 'rgba(14, 165, 233, 0.08)',
            pill: '#0ea5e9',
        },
        {
            stage: 'Human Interview',
            sublabel: 'Invited to panel',
            count: 94,
            percentage: 1.1,
            gradient: 'linear-gradient(90deg, #10b981, #34d399)',
            lightBg: 'rgba(16, 185, 129, 0.08)',
            pill: '#10b981',
        },
        {
            stage: 'Offers Extended',
            sublabel: 'Hire offers sent',
            count: 12,
            percentage: 0.14,
            gradient: 'linear-gradient(90deg, #f59e0b, #fbbf24)',
            lightBg: 'rgba(245, 158, 11, 0.08)',
            pill: '#f59e0b',
        },
    ];

    return (
        <div
            className="p-6 rounded-2xl flex flex-col min-h-[420px]"
            style={{
                background: 'var(--glass-bg)',
                backdropFilter: 'var(--glass-blur)',
                WebkitBackdropFilter: 'var(--glass-blur)',
                border: '1px solid var(--glass-border)',
                boxShadow: 'var(--glass-shadow)',
            }}
        >
            {/* Header */}
            <div className="flex justify-between items-center mb-6">
                <div>
                    <h3 className="font-semibold text-base text-brand-light-textPrimary">
                        Hiring Funnel
                    </h3>
                    <p className="text-xs text-brand-light-textSecondary mt-0.5">Pipeline conversion ┬╖ Last 30 days</p>
                </div>
                <span
                    className="text-xs font-medium px-3 py-1.5 rounded-full"
                    style={{
                        background: 'rgba(90, 70, 218, 0.08)',
                        color: '#5A46DA',
                        border: '1px solid rgba(90, 70, 218, 0.15)',
                    }}
                >
                    Live
                </span>
            </div>

            {/* Funnel bars */}
            <div className="flex-1 flex flex-col justify-center space-y-3">
                {funnel.map((step, idx) => {
                    const maxCount = funnel[0].count;
                    const barWidth = Math.max(8, (step.count / maxCount) * 100);

                    return (
                        <div key={step.stage} className="group">
                            {/* Label row */}
                            <div className="flex items-center justify-between mb-1.5">
                                <div className="flex items-center gap-2">
                                    <span
                                        className="w-2 h-2 rounded-full flex-shrink-0"
                                        style={{ background: step.pill }}
                                    />
                                    <div>
                                        <span className="text-sm font-medium text-brand-light-textPrimary">{step.stage}</span>
                                        <span className="text-xs text-brand-light-textSecondary ml-1.5 hidden sm:inline">{step.sublabel}</span>
                                    </div>
                                </div>
                                <div className="flex items-center gap-2 flex-shrink-0">
                                    <span
                                        className="text-xs font-medium px-2 py-0.5 rounded-full"
                                        style={{
                                            background: step.lightBg,
                                            color: step.pill,
                                        }}
                                    >
                                        {step.percentage.toFixed(1)}%
                                    </span>
                                    <span className="text-sm font-bold text-brand-light-textPrimary tabular-nums">
                                        {step.count.toLocaleString()}
                                    </span>
                                </div>
                            </div>

                            {/* Progress bar */}
                            <div
                                className="h-2.5 w-full rounded-full overflow-hidden"
                                style={{ background: 'rgba(230, 230, 240, 0.6)' }}
                            >
                                <div
                                    className="h-full rounded-full transition-all duration-700 ease-out"
                                    style={{
                                        width: `${barWidth}%`,
                                        background: step.gradient,
                                        boxShadow: `0 0 8px ${step.pill}40`,
                                    }}
                                />
                            </div>
                        </div>
                    );
                })}
            </div>

            {/* Footer stats */}
            <div
                className="mt-4 pt-4 flex items-center justify-between"
                style={{ borderTop: '1px solid rgba(230, 230, 240, 0.6)' }}
            >
                <p className="text-xs text-brand-light-textSecondary">
                    Overall conversion: <span className="font-semibold text-brand-violet">0.14%</span>
                </p>
                <button
                    className="text-xs font-medium transition-colors"
                    style={{ color: '#5A46DA' }}
                >
                    View full report ΓåÆ
                </button>
            </div>
        </div>
    );
}

'use client';

import { Video, FileText, CheckCircle2, UserPlus, Zap, Clock } from 'lucide-react';
import { cn } from '@/lib/utils';

export function RecentActivity() {
    const activities = [
        {
            id: 1,
            type: 'interview_completed',
            title: 'AI Screening Completed',
            desc: 'Sarah Jenkins ΓÇö Frontend Engineer role',
            time: '2h ago',
            icon: Video,
            iconBg: 'rgba(90, 70, 218, 0.1)',
            iconColor: '#5A46DA',
            dotColor: '#5A46DA',
            tag: 'Interview',
            tagBg: 'rgba(90, 70, 218, 0.08)',
            tagColor: '#5A46DA',
        },
        {
            id: 2,
            type: 'resume_parsed',
            title: 'Batch Resume Processing',
            desc: '54 new resumes ΓÇö Product Manager role',
            time: '4h ago',
            icon: FileText,
            iconBg: 'rgba(14, 165, 233, 0.1)',
            iconColor: '#0ea5e9',
            dotColor: '#0ea5e9',
            tag: 'Resumes',
            tagBg: 'rgba(14, 165, 233, 0.08)',
            tagColor: '#0ea5e9',
        },
        {
            id: 3,
            type: 'shortlist_ready',
            title: 'Shortlist Generated',
            desc: 'Top 10 candidates ΓÇö Senior Backend Developer',
            time: '1d ago',
            icon: CheckCircle2,
            iconBg: 'rgba(16, 185, 129, 0.1)',
            iconColor: '#10b981',
            dotColor: '#10b981',
            tag: 'Shortlist',
            tagBg: 'rgba(16, 185, 129, 0.08)',
            tagColor: '#10b981',
        },
        {
            id: 4,
            type: 'candidate_added',
            title: 'New Candidate Added',
            desc: 'Alex Moore entered pipeline ΓÇö UX Designer',
            time: '2d ago',
            icon: UserPlus,
            iconBg: 'rgba(244, 63, 94, 0.1)',
            iconColor: '#f43f5e',
            dotColor: '#f43f5e',
            tag: 'Candidate',
            tagBg: 'rgba(244, 63, 94, 0.08)',
            tagColor: '#f43f5e',
        },
    ];

    return (
        <div
            className="p-6 rounded-2xl min-h-[420px] flex flex-col"
            style={{
                background: 'var(--glass-bg)',
                backdropFilter: 'var(--glass-blur)',
                WebkitBackdropFilter: 'var(--glass-blur)',
                border: '1px solid var(--glass-border)',
                boxShadow: 'var(--glass-shadow)',
            }}
        >
            {/* Header */}
            <div className="flex justify-between items-center mb-6">
                <div>
                    <h3 className="font-semibold text-base text-brand-light-textPrimary">Recent Activity</h3>
                    <p className="text-xs text-brand-light-textSecondary mt-0.5">Platform events across all modules</p>
                </div>
                <button
                    className="text-xs font-medium px-3 py-1.5 rounded-full transition-all duration-200"
                    style={{
                        color: '#5A46DA',
                        background: 'rgba(90, 70, 218, 0.06)',
                        border: '1px solid rgba(90, 70, 218, 0.12)',
                    }}
                >
                    View All
                </button>
            </div>

            {/* Activity Feed */}
            <div className="flex-1 space-y-3">
                {activities.map((item, idx) => {
                    const Icon = item.icon;
                    return (
                        <div
                            key={item.id}
                            className="group flex items-start gap-3.5 p-3.5 rounded-xl transition-all duration-200 cursor-pointer"
                            style={{ background: 'transparent' }}
                            onMouseEnter={e => {
                                (e.currentTarget as HTMLDivElement).style.background = 'rgba(90, 70, 218, 0.04)';
                            }}
                            onMouseLeave={e => {
                                (e.currentTarget as HTMLDivElement).style.background = 'transparent';
                            }}
                        >
                            {/* Icon */}
                            <div
                                className="w-9 h-9 rounded-xl flex items-center justify-center flex-shrink-0 mt-0.5 transition-transform duration-200 group-hover:scale-105"
                                style={{ background: item.iconBg }}
                            >
                                <Icon className="w-4 h-4" style={{ color: item.iconColor }} />
                            </div>

                            {/* Content */}
                            <div className="flex-1 min-w-0">
                                <div className="flex items-start justify-between gap-2">
                                    <div className="min-w-0">
                                        <h4 className="text-sm font-semibold text-brand-light-textPrimary leading-tight truncate">
                                            {item.title}
                                        </h4>
                                        <p className="text-xs text-brand-light-textSecondary mt-0.5 leading-relaxed">
                                            {item.desc}
                                        </p>
                                    </div>
                                    <div className="flex flex-col items-end gap-1.5 flex-shrink-0">
                                        <span
                                            className="text-[10px] font-medium px-2 py-0.5 rounded-full whitespace-nowrap"
                                            style={{
                                                background: item.tagBg,
                                                color: item.tagColor,
                                                border: `1px solid ${item.tagColor}20`,
                                            }}
                                        >
                                            {item.tag}
                                        </span>
                                        <div className="flex items-center gap-1 text-[10px] text-brand-light-textSecondary">
                                            <Clock className="w-3 h-3" />
                                            {item.time}
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>
                    );
                })}
            </div>

            {/* Footer */}
            <div
                className="mt-4 pt-4 flex items-center gap-2"
                style={{ borderTop: '1px solid rgba(230, 230, 240, 0.6)' }}
            >
                <Zap className="w-3.5 h-3.5 text-brand-violet" />
                <p className="text-xs text-brand-light-textSecondary">
                    <span className="font-semibold text-brand-light-textPrimary">24 events</span> in the last 7 days
                </p>
            </div>
        </div>
    );
}

'use client';

import { Bell, Search, User } from 'lucide-react';
import { useUiStore } from '@/store/uiStore';
import { cn } from '@/lib/utils';

export function Topbar() {
    const { isSidebarCollapsed } = useUiStore();

    return (
        <header
            className={cn(
                "fixed top-0 right-0 z-30 transition-all duration-300 h-16",
                "flex items-center justify-between px-6",
                isSidebarCollapsed ? "left-[76px]" : "left-[256px]"
            )}
            style={{
                background: 'rgba(247, 248, 252, 0.85)',
                backdropFilter: 'blur(20px)',
                WebkitBackdropFilter: 'blur(20px)',
                borderBottom: '1px solid rgba(230, 230, 240, 0.8)',
                boxShadow: '0 1px 0 rgba(230, 230, 240, 0.5), 0 2px 12px rgba(90, 70, 218, 0.04)',
            }}
        >
            {/* Greeting + Search */}
            <div className="flex items-center gap-6 flex-1">
                <div className="hidden md:block">
                    <h2 className="text-sm font-semibold text-brand-light-textPrimary leading-none">
                        Good morning ≡ƒæï
                    </h2>
                    <p className="text-xs text-brand-light-textSecondary mt-0.5">
                        Here's what's happening today
                    </p>
                </div>

                <div className="relative w-full max-w-xs">
                    <Search className="absolute left-3.5 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-brand-light-textSecondary/60" />
                    <input
                        type="text"
                        placeholder="Search candidates, roles..."
                        className="w-full text-sm py-2 pl-9 pr-4 rounded-xl outline-none transition-all duration-200"
                        style={{
                            background: 'rgba(255, 255, 255, 0.8)',
                            border: '1px solid rgba(230, 230, 240, 0.9)',
                            color: '#1A1A2E',
                        }}
                        onFocus={(e) => {
                            e.currentTarget.style.border = '1px solid rgba(90, 70, 218, 0.4)';
                            e.currentTarget.style.boxShadow = '0 0 0 3px rgba(90, 70, 218, 0.08)';
                        }}
                        onBlur={(e) => {
                            e.currentTarget.style.border = '1px solid rgba(230, 230, 240, 0.9)';
                            e.currentTarget.style.boxShadow = 'none';
                        }}
                    />
                </div>
            </div>

            {/* Right Actions */}
            <div className="flex items-center gap-2 ml-4">
                {/* Notification Bell */}
                <button
                    className="relative p-2.5 rounded-xl transition-all duration-200 group"
                    style={{ background: 'transparent' }}
                    onMouseEnter={e => {
                        (e.currentTarget as HTMLButtonElement).style.background = 'rgba(90, 70, 218, 0.06)';
                    }}
                    onMouseLeave={e => {
                        (e.currentTarget as HTMLButtonElement).style.background = 'transparent';
                    }}
                >
                    <Bell className="w-4.5 h-4.5 text-brand-light-textSecondary group-hover:text-brand-light-textPrimary transition-colors" style={{ width: '18px', height: '18px' }} />
                    {/* Notification badge */}
                    <span
                        className="absolute top-2 right-2 w-2 h-2 rounded-full"
                        style={{
                            background: 'linear-gradient(135deg, #5A46DA, #9B8CFF)',
                            boxShadow: '0 0 0 2px rgba(247, 248, 252, 0.9)',
                        }}
                    />
                </button>

                {/* Divider */}
                <div className="w-px h-6 mx-1" style={{ background: 'rgba(230, 230, 240, 0.9)' }} />

                {/* User Avatar */}
                <button className="flex items-center gap-2.5 pl-1 pr-2 py-1.5 rounded-xl transition-all duration-200 hover:bg-brand-violet/6">
                    <div
                        className="w-8 h-8 rounded-xl flex items-center justify-center overflow-hidden flex-shrink-0"
                        style={{
                            background: 'linear-gradient(135deg, rgba(90,70,218,0.15), rgba(155,140,255,0.1))',
                            border: '1px solid rgba(90, 70, 218, 0.2)',
                        }}
                    >
                        <User className="w-4 h-4 text-brand-violet" />
                    </div>
                    <div className="hidden sm:block text-left">
                        <p className="text-xs font-semibold text-brand-light-textPrimary leading-none">Recruiter</p>
                        <p className="text-[10px] text-brand-light-textSecondary mt-0.5">Admin</p>
                    </div>
                </button>
            </div>
        </header>
    );
}
